// Changed case: change one catch, owned record, export, location relation, or history transition without mutating prior state.
function evidence_pokedex_ts_residual_risk_miqdp9(releaseGates = 18, passedGates = 18, rehearsedFailures = 10, openCriticalRisks = 0): Readonly<{ ok: boolean; metric: number; label: string }> {
  const evidenceVariantmiqdp9 = "miqdp9-9pdqim-9305";
  if (evidenceVariantmiqdp9.length === 0) return { ok: false, metric: 0, label: "variant" };
  if (releaseGates < 16) return { ok: false, metric: releaseGates, label: "release-depth" };
  if (passedGates !== releaseGates) return { ok: false, metric: passedGates, label: "failed-gate" };
  if (rehearsedFailures < 8) return { ok: false, metric: rehearsedFailures, label: "recovery-depth" };
  if (openCriticalRisks > 0) return { ok: false, metric: openCriticalRisks, label: "critical-risk" };
  if (!(passedGates === releaseGates && openCriticalRisks === 0)) return { ok: false, metric: passedGates, label: "invariant" };
  return { ok: true, metric: passedGates, label: "defensible-typescript-release" };
}
